// Predictive feedback controller with temporal scaling
float predictFeedback(float t, float strength, float delay) {
    float pred = sin(t - delay) * strength;
    return clamp(pred, 0.0, 1.0);
}

// Multi-scale temporal model with predictive coupling
float temporalModel(vec2 uv, float t) {
    float base = sin(uv.x * 2.0 + t * 0.5) * sin(uv.y * 1.5 + t * 0.3);

    // Multi-temporal feedback layers
    float layer1 = sin(uv.x * 0.5 + t * 0.1) * sin(uv.y * 0.7 + t * 0.2);
    float layer2 = sin(uv.x * 0.2 + t * 0.05) * sin(uv.y * 0.3 + t * 0.03);

    // Predictive strength modulation
    float predStrength = 0.5 + 0.5 * sin(t * 0.1);
    float predDelay = 0.1 + 0.2 * sin(t * 0.07);

    float feedback = predictFeedback(t, predStrength, predDelay);

    return base + layer1 * 0.3 + layer2 * 0.1 + feedback * 0.4;
}

// Non-local field coupling with predictive adjustment
vec2 fieldCoupling(vec2 uv, float t) {
    vec2 pos = uv * 2.0 - 1.0;
    float dist = length(pos);

    // Predictive field influence
    float fieldInfluence = sin(dist * 3.0 + t * 0.5) * 0.5 + 0.5;
    float fieldMod = 1.0 + 0.3 * sin(t * 0.2 + dist * 2.0);

    vec2 coupling = vec2(
        sin(pos.x * 2.0 + t * 0.3) * fieldInfluence,
        cos(pos.y * 1.5 + t * 0.4) * fieldInfluence
    );

    return coupling * fieldMod;
}

// Controlled evolution with chaos prevention
float controlledEvolution(vec2 uv, float t) {
    float basePattern = temporalModel(uv, t);

    // Non-local coupling
    vec2 coupling = fieldCoupling(uv, t);
    float localCoupling = coupling.x * coupling.y;

    // Predictive temporal derivative estimation
    float dt = 0.01;
    float nextPattern = temporalModel(uv, t + dt);
    float deriv = (nextPattern - basePattern) / dt;

    // Chaos prevention through predictive damping
    float damping = 1.0 - 0.1 * abs(deriv);
    float evolved = basePattern + localCoupling * 0.2;

    return clamp(evolved * damping, -1.0, 1.0);
}

void main() {
    vec2 uv = gl_FragCoord.xy / u_resolution.xy;
    vec2 mouse = u_mouse / u_resolution.xy;

    // Time-based evolution with predictive modeling
    float t = TIME + mouse.x * 0.5;

    // Multi-scale feedback cascade
    float evolution = controlledEvolution(uv, t);

    // Temporal scale coordination
    float scale1 = controlledEvolution(uv * 0.5, t * 1.2);
    float scale2 = controlledEvolution(uv * 0.2, t * 0.8);

    // Predictive feedback blending
    float blend = 0.5 + 0.5 * sin(t * 0.1);
    float final = evolution * (1.0 - blend) + scale1 * blend * 0.5 + scale2 * 0.3;

    // Serene color mapping
    vec3 color = vec3(0.0);
    color.r = 0.3 + 0.3 * sin(final * PI + t * 0.2);
    color.g = 0.4 + 0.3 * sin(final * PI * 0.7 + t * 0.3);
    color.b = 0.5 + 0.3 * sin(final * PI * 1.3 + t * 0.1);

