// Simplex noise implementation
float noise(vec2 st) {
    vec2 i = floor(st);
    vec2 f = fract(st);

    // Four corners in 2D of a tile
    vec2 a = i;
    vec2 b = i + vec2(1.0, 0.0);
    vec2 c = i + vec2(0.0, 1.0);
    vec2 d = i + vec2(1.0, 1.0);

    // Four corners in 2D of a tile
    vec2 p0 = a;
    vec2 p1 = b;
    vec2 p2 = c;
    vec2 p3 = d;

    // Smooth step function
    vec2 u = f * f * (3.0 - 2.0 * f);

    // Dot products
    float n0 = dot(p0, st);
    float n1 = dot(p1, st - vec2(1.0, 0.0));
    float n2 = dot(p2, st - vec2(0.0, 1.0));
    float n3 = dot(p3, st - vec2(1.0, 1.0));

    // Interpolate between corners
    return mix(n0, n1, u.x) + (n2 - n0) * u.y * (1.0 - u.x) + (n3 - n1) * u.x * u.y;
}

// Predictive feedback loop with temporal memory
float predictFeedback(vec2 uv, float t) {
    float base = noise(uv * 2.0 + t * 0.1);
    float feedback = 0.0;

    // Non-local coupling with multiple scales
    for (int i = 0; i < 4; i++) {
        float scale = pow(2.0, float(i));
        float weight = 1.0 / (scale * 2.0);
        vec2 offset = vec2(cos(t * 0.05 * scale), sin(t * 0.03 * scale)) * 0.5;
        feedback += noise((uv + offset) * scale * 0.5 + t * 0.02) * weight;
    }

    // Temporal smoothing
    float history = noise(uv * 2.0 + t * 0.1 - 1.0);
    float prediction = mix(history, feedback, 0.3);

    // Dynamic parameter modulation
    float damping = 0.95 + 0.02 * sin(t * 0.2);
    return mix(prediction, feedback, damping);
}

