    vec3 r2 = fp - 2.0;

    vec3 v0 = ip;
    vec3 v1 = ip + 1.0;
    vec3 v2 = ip + 2.0;

    vec3 h0 = hash33(v0);
    vec3 h1 = hash33(v1);
