    float P_mod_raw = 1.0 / (1.0 + abs_dEdt * 5.0); // Scale factor for sensitivity
    P_mod_raw = clamp(P_mod_raw, 0.1, 1.0); // Ensure P_mod is never zero and has a max

    // P_mod now represents a "memory retention factor".
    // A high P_mod_raw (low dEdt) means more decay, less memory.
    // A low P_mod_raw (high dEdt) means less decay, more memory.
    // Let's invert it for the "decay rate" perspective:
    float decay_rate = mix(0.05, 0.5, P_mod_raw); // When P_mod_raw is low (high dEdt), decay_rate is low (more memory)
                                                 // When P_mod_raw is high (low dEdt), decay_rate is high (less memory)

    // --- Step 5: Incorporate adaptive decay into pattern generation ---
    // We'll use a multi-layered noise function where the influence of past states
    // (simulated by a slightly offset time sample) is modulated by decay_rate.

    vec3 p = vec3(uv * 3.0, time * 0.5);

    // Base pattern
    float n1 = snoise(p + vec3(0.0, 0.0, time * 0.1));

    // "Past state" influence, modulated by decay_rate.
    // A lower decay_rate means the past state (n2) has a stronger influence.
    float past_time_offset = 0.5; // How far in the past to sample
    vec3 p_past = vec3(uv * 3.0, (time - past_time_offset) * 0.5);
    float n2 = snoise(p_past + vec3(0.0, 0.0, (time - past_time_offset) * 0.1));

    // Combine current and past states, with adaptive weighting
    float combined_pattern = mix(n1, n2, clamp(1.0 - decay_rate * 2.0, 0.0, 1.0)); // If decay_rate is low, more n2; if high, more n1

    // Add another layer for detail and subtle movement
    float n3 = snoise(vec3(uv * 8.0 + combined_pattern * 0.5, time * 0.2));

    // Final color based on the combined patterns
    float final_val = (combined_pattern * 0.6 + n3 * 0.4);

    // Apply a smooth color gradient
    vec3 col = mix(vec3(0.1, 0.2, 0.3), vec3(0.8, 0.9, 1.0), final_val);
    col = mix(col, vec3(0.9, 0.7, 0.6), pow(final_val, 3.0));

    // Subtle overlay based on the adaptive decay_rate itself, to visualize its effect indirectly
    col += vec3(decay_rate * 0.1);

    gl_FragColor = vec4(col, 1.0);
}

precision mediump float;
uniform float u_time;
uniform vec2 u_resolution;
uniform vec2 u_mouse;

// Helper function for 2D Simplex Noise
// Source: https://github.com/ashima/webgl-noise/blob/master/src/noise2D.glsl
vec3 mod289(vec3 x) { return x - floor(x * (1.0 / 289.0)) * 289.0; }
vec2 mod289(vec2 x) { return x - floor(x * (1.0 / 289.0)) * 289.0; }
vec3 permute(vec3 x) { return mod289(((x*34.0)+1.0)*x); }

float snoise(vec2 v) {
    const vec4 C = vec4(0.211324865405187, // (3.0-sqrt(3.0))/6.0
                        0.366025403784439, // 0.5*(sqrt(3.0)-1.0)
                       -0.577350269189626, // -1.0 + 2.0 * C.x
                        0.024390243902439); // 1.0 / 41.0
    vec2 i = floor(v + dot(v, C.yy));
    vec2 x0 = v - i + dot(i, C.xx);
    vec2 i0;
    i0 = (x0.x > x0.y) ? vec2(1.0, 0.0) : vec2(0.0, 1.0);
    vec2 x1 = x0.xy + C.xx - i0;
    vec2 x2 = x0.xy + C.zz;
    vec3 p = permute( permute( i.y + vec3(0.0, i0.y, 1.0 )) + i.x + vec3(0.0, i0.x, 1.0 ));
    vec3 m = max(0.5 - vec3(dot(x0,x0), dot(x1,x1), dot(x2,x2)), 0.0);
    m = m * m;
    m = m * m;
    vec3 x = 2.0 * fract(p * C.www) - 1.0;
    vec3 h = abs(x) - 0.5;
    vec3 ox = floor(x + 0.5);
    vec3 a0 = x - ox;
    m *= 1.79284291400159 - 0.85373472095314 * ( a0*a0 + h*h );
    vec3 g;
    g.x = a0.x * x0.x + h.x * x0.y;
    g.yz = a0.yz * vec2(x1.x,x2.x) + h.yz * vec2(x1.y,x2.y);
    return 130.0 * dot(m, g);
}

// Function to calculate a "pattern density" value at a given coordinate and time
// This incorporates a simple temporal feedback loop for density
float getPatternDensity(vec2 p, float t) {
    float n1 = snoise(p * 2.5 + vec2(0.0, t * 0.1));
    float n2 = snoise(p * 5.0 + vec2(t * 0.05, 0.0) + n1 * 0.5);
    float n3 = snoise(p * 10.0 + vec2(0.0, t * 0.02) + n2 * 0.3);
    return (n1 + n2 * 0.5 + n3 * 0.25) / 1.75; // Normalize to approx -1 to 1
}

// Function to estimate the temporal derivative of pattern density
// This is a simplified finite difference over a small time delta
float getDensityRateOfChange(vec2 p, float t, float dt) {
    float density_now = getPatternDensity(p, t);
    float density_prev = getPatternDensity(p, t - dt);
    return (density_now - density_prev) / dt;
}

void main() {
    vec2 uv = gl_FragCoord.xy / u_resolution.xy;
    uv.x *= u_resolution.x / u_resolution.y; // Aspect correction
    vec2 p = uv * 3.0 - vec2(1.5); // Scale and center for noise

    float time_delta = 0.05; // Small time step for derivative estimation

    // Calculate current pattern density
    float current_density = getPatternDensity(p, u_time);

    // Calculate rate of change of pattern density (d/dt)E
    float density_rate_of_change = getDensityRateOfChange(p, u_time, time_delta);

    // Map (d/dt)E to P_mod (boundary stiffness)
    // When density changes rapidly (high abs(d/dt)E), boundaries should be stiffer (higher P_mod)
    // When density changes slowly, boundaries should be softer (lower P_mod)
    // Scale density_rate_of_change to a reasonable range for modulation
    float p_mod_raw = abs(density_rate_of_change) * 0.5 + 0.1; // Base stiffness + dynamic part
    float p_mod = clamp(p_mod_raw, 0.2, 1.5); // Clamp P_mod to a reasonable range

    // Apply P_mod to influence the 'boundary' or 'edge' detection
    // A higher P_mod makes the 'boundary' sharper/stiffer
    float value = current_density;

    // Use a step-like function or a smoothed step to create boundaries
    // The 'stiffness' (p_mod) influences the steepness of the gradient or the threshold
    float threshold = 0.0;
    float softness = 0.1 / p_mod; // Higher P_mod -> smaller softness -> sharper boundary

    float boundary_strength = smoothstep(threshold - softness, threshold + softness, value);

    // Introduce a subtle temporal wobble for organic feel
    boundary_strength += snoise(p * 0.5 + u_time * 0.2) * 0.05;

    // Apply a second layer of noise for fine detail and organic texture
    float detail_noise = snoise(p * 20.0 + u_time * 0.01) * 0.1;
    detail_noise = pow(abs(detail_noise), 2.0) * sign(detail_noise); // Bias towards center

    float final_value = boundary_strength + detail_noise * (1.0 - boundary_strength);
    final_value = clamp(final_value, 0.0, 1.0);

    // Color mapping for a serene aesthetic
    vec3 color1 = vec3(0.1, 0.2, 0.3); // Dark blue-grey
    vec3 color2 = vec3(0.8, 0.9, 0.95); // Light almost white blue

    vec3 final_color = mix(color1, color2, final_value);

    gl_FragColor = vec4(final_color, 1.0);
}

precision mediump float;

uniform float u_time;
uniform vec2 u_resolution;
uniform vec2 u_mouse;

// Hash function from Inigo Quilez for pseudo-randomness
float hash11(float p) {
    p = fract(p * .1031);
    p *= p + 33.33;
    p = p * p + p;
    return fract(p);
}

// Value noise from Inigo Quilez
float noise(vec2 p) {
    vec2 i = floor(p);
    vec2 f = fract(p);

    // Four corners in 2D of a unit square
    float a = hash11(dot(i, vec2(5.0, 1.0)));
    float b = hash11(dot(i + vec2(1.0, 0.0), vec2(5.0, 1.0)));
    float c = hash11(dot(i + vec2(0.0, 1.0), vec2(5.0, 1.0)));
    float d = hash11(dot(i + vec2(1.0, 1.0), vec2(5.0, 1.0)));

    vec2 u = f * f * (3.0 - 2.0 * f); // Smoothstep
    return mix(a, b, u.x) + (c - a) * u.y * (1.0 - u.x) + (d - b) * u.x * u.y;
}

// FBM (Fractal Brownian Motion) for base pattern, serving as E_base
float fbm(vec2 p, float time) {
    float f = 0.0;
    float amp = 0.5;
    float freq = 1.0;
    for (int i = 0; i < 4; i++) { // Multiple octaves for emergent complexity
        f += noise(p * freq + time * 0.1) * amp;
        freq *= 2.0;
        amp *= 0.5;
        // Subtle self-distortion within the FBM for foundational temporal dynamics
        p += vec2(sin(time * 0.02 * float(i)), cos(time * 0.03 * float(i)));
    }
    return f;
}

// Dynamic flow field generator
vec2 get_flow(vec2 p, float time) {
    // Blending noise and simple harmonic waves for a rich, evolving flow
    vec2 flow_noise = vec2(noise(p * 0.5 + time * 0.1), noise(p * 0.5 + time * 0.1 + 10.0));
    flow_noise = flow_noise * 2.0 - 1.0; // Remap to [-1, 1]

    vec2 wave_flow = vec2(sin(p.y * 0.3 + time * 0.2), cos(p.x * 0.4 + time * 0.3));

    // Normalize the combined flow to maintain consistent influence direction
    return normalize(flow_noise * 0.5 + wave_flow * 0.5);
}

// Core function to calculate local pattern correlation (E), incorporating flow modulation
float calculate_E(vec2 frag_uv, float time, float flow_mod_strength) {
    vec2 p = frag_uv * 4.0; // Scale coordinates for pattern detail
    p.x -= time * 0.05;     // Gentle global drift for continuous evolution

    // Apply the global flow field, dynamically modulated by flow_mod_strength
    vec2 flow_dir = get_flow(p, time);
    p += flow_dir * flow_mod_strength * 0.3; // flow_mod_strength scales distortion intensity

    // Introduce additional subtle wave-based distortion for micro-animations
    p += vec2(sin(p.y * 0.2 + time * 0.1), cos(p.x * 0.3 + time * 0.05)) * 0.1;

    // Return the FBM value as the pattern's intensity (E)
    return fbm(p, time);
}

void main() {
    vec2 uv = gl_FragCoord.xy / u_resolution.xy;
    uv.x *= u_resolution.x / u_resolution.y; // Aspect ratio correction

    float time_base = u_time * 0.1; // Slower time for overall systemic evolution
    float dt = 0.005;               // Small temporal step for calculating the rate of change

    // --- Hypothesis: (d/dt)E -> P_mod ---
    // This section implements the core feedback loop for self-correcting flow topologies.
    // P_mod (flow_mod_strength) is dynamically adjusted based on the observed rate of change in E.

    // 1. Calculate E at the current time (E_curr) using a baseline P_mod.
    //    This captures the inherent temporal dynamics of the pattern.
    float P_mod_baseline = 0.5 + sin(time_base * 0.5) * 0.2; // Baseline P_mod with gentle oscillation
    float E_curr = calculate_E(uv, time_base, P_mod_baseline);

    // 2. Calculate E at a slightly earlier time (E_prev) for temporal differencing.
    float E_prev = calculate_E(uv, time_base - dt, P_mod_baseline);

    // 3. Determine the local rate of change of pattern correlation (dE_dt_local).
    //    This acts as a local 'cognitive' signal indicating pattern stability or flux.
    float dE_dt_local = (E_curr - E_prev) / dt;

    // 4. Map dE_dt_local to the *feedback-adjusted* P_mod_strength.
    //    The hypothesis states that the rate of change drives flow modulation.
    //    Higher absolute dE_dt_local (faster change) leads to stronger flow modulation,
    //    prompting the system to reconfigure its flow topology for self-correction.
    float P_mod_feedback = abs(dE_dt_local) * 2.0; // Scale the derivative to influence flow strength
    P_mod_feedback = clamp(P_mod_feedback, 0.2, 1.2); // Clamp to prevent extreme values and ensure stability

    // 5. Recalculate the final pattern (final_E) using the feedback-adjusted P_mod.
    //    This is where the emergent self-correction manifests: the flow topology
    //    dynamically adapts to the pattern's internal rate of change, aiming for
    //    coherent, evolving structures and anticipatory stability.
    float final_E = calculate_E(uv, time_base, P_mod_feedback);

    // --- Coloring for profound tranquility and low visual friction ---
    vec3 color = vec3(0.0);
    // Base gradient: transitioning from deep, cool tones to bright, ethereal hues
    vec3 col_deep = vec3(0.05, 0.1, 0.15); // Dark blue-green
    vec3 col_light = vec3(0.8, 0.9, 1.0);  // Ethereal light blue-white
    color = mix(col_deep, col_light, final_E);

    // Introduce a secondary warm gradient to add subtle depth and organic feel
    vec3 col_warm_accent = vec3(0.9, 0.8, 0.7); // Soft peach/gold
    color = mix(color, col_warm_accent, final_E * final_E * 0.5); // Blend based on squared intensity for softness

    // Add delicate highlights/shadows based on dE_dt_local, subtly emphasizing areas of active change
    // This provides visual cues of the distributed intelligence without introducing visual friction.
    float detail_mod = sin(dE_dt_local * 15.0) * 0.03; // Small amplitude for micro-animation
    color += detail_mod;

    // Apply a final smoothstep to enhance overall softness and contemplative quality
    color = smoothstep(0.0, 1.0, color);

    gl_FragColor = vec4(color, 1.0);
}

precision mediump float;

uniform float u_time;
uniform vec2 u_resolution;
uniform vec2 u_mouse;

// Hash function for random values
float hash(vec2 p) {
    p = fract(p * 0.3183099 + vec2(0.1));
    p *= p + 0.19105946;
    return fract(p.x*p.y);
}

// 2D Simplex Noise (from Ashima Arts, modified for GLSL ES 1.0)
vec3 mod289(vec3 x) { return x - floor(x * (1.0 / 289.0)) * 289.0; }
vec2 mod289(vec2 x) { return x - floor(x * (1.0 / 289.0)) * 289.0; }
vec3 permute(vec3 x) { return mod289(((x*34.0)+1.0)*x); }
float snoise(vec2 v) {
    const vec4 C = vec4(0.211324865405187, 0.366025403784439, -0.577350269189626, 0.024390243902439);
    vec2 i = floor(v + dot(v, C.yy));
    vec2 x0 = v - i + dot(i, C.xx);
    vec2 i1;
    i1 = (x0.x > x0.y) ? vec2(1.0, 0.0) : vec2(0.0, 1.0);
    vec4 x12 = x0.xyxy + C.xxzz;
    x12.x += i1.x;
    x12.y += i1.y;
    x12.z += 1.0;
    x12.w += 1.0;
    i = mod289(i);
    vec3 p = permute(permute(i.y + vec3(0.0, i1.y, 1.0 )) + i.x + vec3(0.0, i1.x, 1.0 ));
    vec3 m = max(0.5 - vec3(dot(x0,x0), dot(x12.xy,x12.xy), dot(x12.zw,x12.zw)), 0.0);
    m = m*m;
    m = m*m;
    vec3 x = 2.0 * fract(p * C.www) - 1.0;
    vec3 h = abs(x) - 0.5;
    vec3 ox = floor(x + 0.5);
    vec3 a0 = x - ox;
    m *= 1.79284291400159 - 0.85373472095314 * ( a0*a0 + h*h );
    vec3 g;
    g.x  = a0.x  * x0.x  + h.x  * x0.y;
    g.y  = a0.y  * x12.x + h.y  * x12.y;
    g.z  = a0.z  * x12.z + h.z  * x12.w;
    return 130.0 * dot(m, g);
}


// Function to simulate a localized 'emergent state' E
// This could be a complex pattern derived from noise, waves, and feedback.
float getEmergentState(vec2 uv, float t) {
    float n1 = snoise(uv * 3.0 + vec2(t * 0.1, t * 0.05));
    float n2 = snoise(uv * 7.0 - vec2(t * 0.08, t * 0.12));
    float n3 = snoise(uv * 12.0 + vec2(t * 0.03, t * 0.09));

    // Combine noise layers, add some wave-like motion
    float E = (n1 + n2 * 0.5 + n3 * 0.25);
    E += sin(dot(uv, vec2(10.0, 7.0)) + t * 0.5) * 0.3;
    E = fract(E * 0.5 + 0.5); // Normalize to [0,1] and make it more "fluid"
    return E;
}

void main() {
    vec2 uv = gl_FragCoord.xy / u_resolution.xy;
    uv.x *= u_resolution.x / u_resolution.y; // Aspect ratio correction

    float t = u_time * 0.2;

    // --- Core Systemic Intelligence: (d/dt)E -> P_mod ---

    // 1. Calculate current emergent state E(t)
    float E_current = getEmergentState(uv, t);

    // 2. Predict future emergent state E(t + dt)
    // Use a small time step for the derivative approximation
    float dt = 0.01; 
    float E_future = getEmergentState(uv, t + dt);

    // 3. Approximate the rate of change (d/dt)E
    // This is the "predicted future divergence"
    float dE_dt = (E_future - E_current) / dt;

    // 4. Modulate localized feedback loop strength (P_mod) based on dE_dt
    // The hypothesis states P_mod increases proportionally to dE_dt to resist entropy.
    // We want P_mod to be higher when the pattern is changing rapidly,
    // implying it's diverging from a stable state or experiencing high "entropy".
    // This feedback should then "pull" the pattern back or reinforce its structure.
    float P_mod = abs(dE_dt) * 5.0; // Higher P_mod for higher divergence
    P_mod = clamp(P_mod, 0.1, 2.0); // Keep P_mod within a reasonable range

    // --- Apply P_mod to influence the final pattern ---

    // Use P_mod to adjust parameters of the pattern generation, 
    // simulating an anticipatory control mechanism.
    // For instance, P_mod can influence a "damping" factor or "intensity" of a layer.

    float base_pattern = snoise(uv * 2.0 + t * 0.05);

    // Re-evaluate E_current with P_mod influencing its internal dynamics.
    // This simulates the feedback loop: dE_dt -> P_mod -> E_new
    // We can use P_mod to subtly warp coordinates or adjust amplitudes.
    vec2 warped_uv = uv + vec2(snoise(uv * 5.0 + t * 0.1) * 0.05 * P_mod, 
                               snoise(uv * 6.0 - t * 0.07) * 0.05 * P_mod);

    float E_final = getEmergentState(warped_uv, t);

    // Introduce a secondary, more subtle layer influenced by P_mod
    // This layer can be seen as the system actively "sculpting" details
    // to counteract the divergence.
    float sculpting_layer = snoise(uv * 15.0 + t * 0.3 + E_final * 2.0);
    sculpting_layer = pow(abs(sculpting_layer), 2.0) * sign(sculpting_layer); // Sharpen
    sculpting_layer *= (1.0 - P_mod * 0.3); // Less sculpting when P_mod is high (more active stabilization)

    // Combine for final color
    float final_value = E_final * 0.7 + base_pattern * 0.3 + sculpting_layer * 0.1;

    // Smooth step for softer forms
    final_value = smoothstep(0.3, 0.7, final_value);

    // Apply a gentle color gradient
    vec3 color1 = vec3(0.05, 0.1, 0.2); // Deep blue
    vec3 color2 = vec3(0.3, 0.5, 0.7); // Mid blue
    vec3 color3 = vec3(0.8, 0.9, 0.95); // Light almost white

    vec3 final_color = mix(color1, color2, final_value);
    final_color = mix(final_color, color3, smoothstep(0.6, 1.0, final_value));

    // Subtle temporal modulation on color for living feel
    final_color += sin(u_time * 0.5 + uv.x * 3.0) * 0.03;

    gl_FragColor = vec4(final_color, 1.0);
}

precision mediump float;

uniform float u_time;
uniform vec2 u_resolution;
uniform vec2 u_mouse;

// Hash function for pseudo-random numbers
float hash(vec2 p) {
    p = fract(p * 0.3183099 + 0.1);
    p *= p + 0.1;
    return fract(p.x * p.y);
}

// 2D Simplex Noise (simplified for brevity)
// From IQ's code
vec2 hash2(vec2 p) {
    p = vec2(dot(p, vec2(127.1, 311.7)), dot(p, vec2(269.5, 183.3)));
    return fract(sin(p) * 43758.5453);
}

float noise(vec2 p) {
    vec2 i = floor(p);
    vec2 f = fract(p);

    vec2 u = f * f * (3.0 - 2.0 * f);

    float a = dot(hash2(i + vec2(0.0, 0.0)), vec2(f.x - 0.0, f.y - 0.0));
    float b = dot(hash2(i + vec2(1.0, 0.0)), vec2(f.x - 1.0, f.y - 0.0));
    float c = dot(hash2(i + vec2(0.0, 1.0)), vec2(f.x - 0.0, f.y - 1.0));
    float d = dot(hash2(i + vec2(1.0, 1.0)), vec2(f.x - 1.0, f.y - 1.0));

    return mix(mix(a, b, u.x), mix(c, d, u.x), u.y);
}

// Function to calculate a "pseudo-energy" E for a given coordinate
// This represents the local system state
float calculateEnergy(vec2 p, float t, float freqScale) {
    float n1 = noise(p * freqScale + t * 0.1);
    float n2 = noise(p * freqScale * 2.0 - t * 0.05);
    return fract(n1 + n2 * 0.5); // A simple local energy proxy
}

void main() {
    vec2 uv = gl_FragCoord.xy / u_resolution.xy;
    vec2 ar_uv = uv * u_resolution.xy / u_resolution.y; // Aspect ratio corrected

    // Base frequency for the grid-like structure
    float gridFreq = 2.0 + sin(u_time * 0.05) * 0.5;

    // Calculate local energy at current time (E_t)
    float E_t = calculateEnergy(ar_uv, u_time, gridFreq);

    // Calculate local energy at a slightly previous time (E_t_minus_dt)
    // This allows us to approximate dE/dt locally
    float dt_approx = 0.01; // Small time step for derivative approximation
    float E_t_minus_dt = calculateEnergy(ar_uv, u_time - dt_approx, gridFreq);

    // Approximate the rate of change of local energy (dE/dt)
    // We are interested in the magnitude of change, so abs()
    float dE_dt_local = abs(E_t - E_t_minus_dt) / dt_approx;

    // Hypothesis: Damping factor P_mod scales inversely with dE/dt
    // A higher rate of change means the system is becoming unstable, so we need more damping.
    // So, P_mod should increase with dE_dt_local.
    // Let's use a sigmoid-like function to map dE_dt_local to a damping influence.
    // This creates a feedback loop: if energy changes rapidly, damping increases.
    float damping_influence = smoothstep(0.0, 0.5, dE_dt_local * 5.0); // Scale and smooth

    // Core wave pattern, influenced by time and space
    float wave_val = sin(ar_uv.x * 10.0 + u_time * 0.5) * cos(ar_uv.y * 10.0 - u_time * 0.3);

    // Introduce a secondary, lower frequency pattern for organic flow
    float flow_val = noise(ar_uv * 3.0 + u_time * 0.1) * 0.5 + noise(ar_uv * 5.0 - u_time * 0.08) * 0.3;

    // Combine these, then apply the anticipatory damping.
    // The damping_influence reduces the overall intensity of the pattern
    // when the system is changing rapidly (dE_dt_local is high).
    // This makes the pattern "calm down" when it's too active.
    float final_pattern = (wave_val + flow_val) * (1.0 - damping_influence * 0.8); // 0.8 to not fully dampen

    // Add a base noise for subtle texture and ensure some activity even when damped
    float base_noise = noise(ar_uv * 15.0 + u_time * 0.02) * 0.1;

    float color_component = fract(final_pattern * 0.5 + E_t * 0.3 + base_noise);

    // Smoothstep for a soft, tranquil color mapping
    vec3 color = vec3(
        smoothstep(0.0, 1.0, color_component + 0.1),
        smoothstep(0.0, 1.0, color_component * 0.8 + 0.2),
        smoothstep(0.0, 1.0, color_component * 0.6 + 0.3)
    );

    // Subtle color shift based on mouse for interaction
    vec3 mouse_color_shift = vec3(u_mouse.x / u_resolution.x, u_mouse.y / u_resolution.y, 0.5);
    color = mix(color, mouse_color_shift, 0.05); // Very subtle influence

